import base64
import zlib
import requests
from urllib.parse import quote_plus
from datetime import datetime

def build_saml_request(destination_url, user_info):
    saml_request_template = '''
    <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" 
                        ID="_{}" 
                        Version="2.0" 
                        IssueInstant="{}" 
                        Destination="{}" 
                        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" 
                        AssertionConsumerServiceURL="{}">
        <saml:Issuer>{}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified" AllowCreate="true"/>
    </samlp:AuthnRequest>
    '''
    
    request_id = "id-" + datetime.utcnow().strftime("%Y%m%d%H%M%S")
    issue_instant = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    acs_url = user_info.get('acs_url', '')
    issuer = user_info.get('issuer', '')

    saml_request = saml_request_template.format(request_id, issue_instant, destination_url, acs_url, issuer)
    compressed_request = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded_request = base64.b64encode(compressed_request).decode('utf-8')
    return quote_plus(encoded_request)

def post_saml_request(destination_url, user_info):
    saml_request = build_saml_request(destination_url, user_info)
    response = requests.post(destination_url, data={'SAMLRequest': saml_request})
    return response

